// 이미지 생성 — 입력 검증 + 프롬프트 조합 + kie.ai 생성 + MinIO 저장
const body = $input.first().json.body || $input.first().json;

// 입력 검증
const prompt = body.prompt;
if (!prompt) throw new Error('prompt는 필수입니다.');
const aspectRatio = body.aspect_ratio || '9:16';
if (!['9:16', '16:9', '1:1'].includes(aspectRatio)) throw new Error('aspect_ratio: 9:16 / 16:9 / 1:1');
const count = Math.min(3, Math.max(1, parseInt(body.count) || 1));
const slots = body.slots || {};

// 슬롯별 vision_analysis 수집 (use: true만)
const promptParts = [];

if (slots.subject?.use && slots.subject?.vision_analysis) {
  promptParts.push(`[Subject - include this person/object exactly as described]: ${slots.subject.vision_analysis}`);
}
if (slots.scene?.use && slots.scene?.vision_analysis) {
  promptParts.push(`[Scene - use this background/setting]: ${slots.scene.vision_analysis}`);
}
if (slots.style?.use && slots.style?.vision_analysis) {
  promptParts.push(`[Style - apply this mood/art style]: ${slots.style.vision_analysis}`);
}

// 최종 프롬프트
promptParts.push(prompt);
const finalPrompt = promptParts.join('\n');

// kie.ai 이미지 생성
const apiKey = $env.KIEAI_API_KEY;

async function pollTask(taskId) {
  for (let i = 0; i < 60; i++) {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.kie.ai/api/v1/jobs/recordInfo?taskId=${taskId}`,
      headers: { 'Authorization': `Bearer ${apiKey}` },
      json: true
    });
    const state = resp?.data?.state;
    if (state === 'success') {
      const result = JSON.parse(resp.data.resultJson || '{}');
      return result.resultUrls || [];
    }
    if (state === 'failed' || state === 'fail') {
      throw new Error(`이미지 생성 실패: ${resp.data.failMsg || state}`);
    }
    await new Promise(r => setTimeout(r, 5000));
  }
  throw new Error('이미지 생성 타임아웃 (300초)');
}

// count개 이미지 생성 (순차 요청)
const taskIds = [];
for (let i = 0; i < count; i++) {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.kie.ai/api/v1/jobs/createTask',
    headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
    body: { model: 'nano-banana-pro', input: { prompt: finalPrompt, aspect_ratio: aspectRatio } },
    json: true
  });
  const taskId = resp?.data?.taskId;
  if (!taskId) throw new Error(`이미지 생성 요청 실패 (${i+1}): ` + JSON.stringify(resp).substring(0, 200));
  taskIds.push(taskId);
}

// 폴링 (순차)
const allUrls = [];
for (const taskId of taskIds) {
  const urls = await pollTask.call(this, taskId);
  allUrls.push(...urls);
}

if (allUrls.length === 0) throw new Error('생성된 이미지 없음');

return [{
  json: {
    success: true,
    count: allUrls.length,
    images: allUrls,
    prompt: finalPrompt,
    aspect_ratio: aspectRatio,
    slots_used: {
      subject: !!(slots.subject?.use),
      scene: !!(slots.scene?.use),
      style: !!(slots.style?.use)
    }
  }
}];
